graphql.query:
query IntrospectionQuery {
  __schema {
    queryType { name }
    mutationType { name }
    subscriptionType { name }
    types {
      ...FullType
    }
    directives {
      name
      description
      locations
      args {
        ...InputValue
      }
    }
  }
}

fragment FullType on __Type {
  kind
  name
  description
  fields(includeDeprecated: true) {
    name
    description
    args {
      ...InputValue
    }
    type {
      ...TypeRef
    }
    isDeprecated
    deprecationReason
  }
  inputFields {
    ...InputValue
  }
  interfaces {
    ...TypeRef
  }
  enumValues(includeDeprecated: true) {
    name
    description
    isDeprecated
    deprecationReason
  }
  possibleTypes {
    ...TypeRef
  }
}

fragment InputValue on __InputValue {
  name
  description
  type { ...TypeRef }
  defaultValue
}

fragment TypeRef on __Type {
  kind
  name
  ofType {
    kind
    name
    ofType {
      kind
      name
      ofType {
        kind
        name
        ofType {
          kind
          name
          ofType {
            kind
            name
            ofType {
              kind
              name
              ofType {
                kind
                name
              }
            }
          }
        }
      }
    }
  }
}

query Pools {
    pools(first: 100) {
        id
        token0 {
            id
            symbol
        }
        token1 {
            id
            symbol
        }
    }
}

query HighestLiquidityPoolsSincePastWeek($since: BigInt!) {
    pools(
        first: 100
        orderBy: liquidity
        orderDirection: desc
        where: { createdAtTimestamp_gte: $since }
    ) {
        id
        token0 {
            id
            symbol
        }
        token1 {
            id
            symbol
        }
    }
}

query Pool($id: ID!) {
    pools(
        where: {
            id: $id
        }
    ) {
        id
        token0 {
            id
            symbol
            derivedETH
        }
        token1 {
            id
            symbol
            derivedETH
        }
        liquidity
        token0Price
        token1Price
        volumeToken0
        volumeToken1
        volumeUSD
        totalValueLockedUSD
    }
}
